import SwiftUI

struct MeasureRootView: View {
    @State private var measurementText = "Tap two points to measure"

    var body: some View {
        ZStack {
            ARViewContainer(measurementText: $measurementText)
                .ignoresSafeArea()

            VStack {
                Spacer()
                Text(measurementText)
                    .font(.title2)
                    .fontWeight(.semibold)
                    .padding(.horizontal, 24)
                    .padding(.vertical, 12)
                    .background(.ultraThinMaterial, in: Capsule())
                    .padding(.bottom, 40)
            }
        }
    }
}
